 13→// fakeProvider is a test AuthProvider that returns a fixed identity.
 14→type fakeProvider struct {
 15→	name     string
 16→	identity *Identity
 17→	err      error
 18→}
 19→
 20→func (f *fakeProvider) Provider() string { return f.name }
 21→
 22→func (f *fakeProvider) AuthorizationURL(_ context.Context, state string) (string, error) {
 23→	return "https://fake-provider.example.com/auth?state=" + state, nil
 24→}
 25→
 26→func (f *fakeProvider) HandleCallback(_ context.Context, _ CallbackRequest) (*Identity, error) {
 27→	if f.err != nil {
 28→		return nil, f.err
 29→	}
 30→	return f.identity, nil
