 40→// doOAuthCallback simulates a full OAuth callback request with state cookie.
 41→func (te *testEnv) doOAuthCallback(provider, code, state string) *httptest.ResponseRecorder {
 42→	r := httptest.NewRequest("GET", "/auth/"+provider+"/callback?code="+code+"&state="+state, nil)
 43→	r.AddCookie(&http.Cookie{Name: "oauth_state", Value: state})
 44→	w := httptest.NewRecorder()
 45→	te.mux.ServeHTTP(w, r)
 46→	return w
 47→}
