 49→func TestOAuthCallback_NewUser(t *testing.T) {
 50→	te := newOAuthTestEnv(&Identity{
 51→		Subject:     "google-sub-123",
 52→		Email:       "alice@acme.com",
 53→		DisplayName: "Alice Smith",
 54→		AvatarURL:   "https://example.com/avatar.jpg",
 55→		Provider:    "fake",
 56→	})
 57→
 58→	w := te.doOAuthCallback("fake", "auth-code", "test-state")
 59→
 60→	// Should redirect (307) on success.
 61→	if w.Code != http.StatusTemporaryRedirect {
 62→		t.Fatalf("status = %d, want %d; body: %s", w.Code, http.StatusTemporaryRedirect, w.Body.String())
 63→	}
 64→
 65→	// User should be created.
 66→	user, err := te.users.GetByEmail(t.Context(), "alice@acme.com")
 67→	if err != nil {
 68→		t.Fatalf("user not found: %v", err)
 69→	}
 70→	if user.DisplayName != "Alice Smith" {
 71→		t.Errorf("display_name = %q, want Alice Smith", user.DisplayName)
 72→	}
 73→	if user.AuthProvider != "fake" {
 74→		t.Errorf("auth_provider = %q, want fake", user.AuthProvider)
 75→	}
 76→	if user.AuthProviderSubjectID != "google-sub-123" {
 77→		t.Errorf("subject = %q, want google-sub-123", user.AuthProviderSubjectID)
 78→	}
 79→	if user.Status != model.UserStatusActive {
 80→		t.Errorf("status = %q, want active (OAuth skips verification)", user.Status)
 81→	}
 82→
 83→	// Enterprise should be created.
 84→	ent, err := te.ents.Get(t.Context(), user.EnterpriseID)
 85→	if err != nil {
 86→		t.Fatalf("enterprise not found: %v", err)
 87→	}
 88→	if ent.Personal {
 89→		t.Error("expected organizational enterprise for acme.com")
 90→	}
 91→
 92→	// Session should be created.
 93→	if te.sessions.count() != 1 {
 94→		t.Errorf("sessions = %d, want 1", te.sessions.count())
 95→	}
 96→}
