  3→const TOKEN_KEY = 'aileron_access_token';
  4→const REFRESH_KEY = 'aileron_refresh_token';
  5→
  6→/** Reactive auth state using Svelte 5 runes via module-level $state. */
  7→let _token = $state<string | null>(null);
  8→let _user = $state<AuthUser | null>(null);
  9→
 10→export interface AuthUser {
 11→	id: string;
 12→	email: string;
 13→	display_name: string;
 14→	avatar_url?: string;
 15→	role: string;
 16→	enterprise_id: string;
 17→}
 18→
 19→/** Initialize auth state from localStorage (call once on app mount). */
 20→export function initAuth() {
 21→	if (typeof window === 'undefined') return;
 22→	_token = localStorage.getItem(TOKEN_KEY);
 23→	if (_token) {
 24→		fetchCurrentUser().catch(() => clearAuth());
 25→	}
 26→}
 27→
 28→/** Returns the current access token, or null. */
 29→export function getToken(): string | null {
 30→	return _token;
 31→}
 32→
 33→/** Returns the current user, or null. */
 34→export function getUser(): AuthUser | null {
 35→	return _user;
 36→}
 37→
 38→/** Returns true if the user is authenticated. */
 39→export function isAuthenticated(): boolean {
 40→	return _token !== null;
 41→}
 42→
 43→/** Store tokens after login/signup and fetch user profile. */
 44→export async function setAuth(accessToken: string, refreshToken?: string) {
 45→	_token = accessToken;
 46→	localStorage.setItem(TOKEN_KEY, accessToken);
 47→	if (refreshToken) {
 48→		localStorage.setItem(REFRESH_KEY, refreshToken);
 49→	}
 50→	await fetchCurrentUser();
 51→}
 52→
 53→/** Clear auth state (logout). */
 54→export function clearAuth() {
 55→	_token = null;
 56→	_user = null;
 57→	localStorage.removeItem(TOKEN_KEY);
 58→	localStorage.removeItem(REFRESH_KEY);
 59→}
 60→
 61→/** Attempt to refresh the access token using the stored refresh token. */
 62→export async function refreshAuth(): Promise<boolean> {
 63→	const refreshToken = localStorage.getItem(REFRESH_KEY);
